create table if not exists service_blueprints (id text primary key, service_code text not null, name text not null, family text, deployment_modes jsonb default '[]', modules jsonb default '[]', rules jsonb default '[]', workflows jsonb default '[]', city_deployments jsonb default '[]', version text default '1.0.0', readiness int default 0, margin_target numeric default 0, expansion_priority int default 0, compliance_level text default 'basic', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists service_modules_registry (key text primary key, label text not null, description text, default_enabled boolean default false, enterprise_impact text, required_role text, cost_weight numeric default 0);
create table if not exists service_blueprint_versions (id uuid primary key default gen_random_uuid(), blueprint_id text references service_blueprints(id), version text not null, snapshot jsonb not null, created_at timestamptz default now(), created_by text);
